import React, { useCallback, useState } from 'react';
import { Upload, Image as ImageIcon, X } from 'lucide-react';

interface ImageUploaderProps {
  onImageSelect: (file: File) => void;
  isLoading: boolean;
}

const ImageUploader: React.FC<ImageUploaderProps> = ({ onImageSelect, isLoading }) => {
  const [preview, setPreview] = useState<string | null>(null);
  const [isDragging, setIsDragging] = useState(false);

  const handleFile = (file: File) => {
    if (file && file.type.startsWith('image/')) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setPreview(reader.result as string);
      };
      reader.readAsDataURL(file);
      onImageSelect(file);
    }
  };

  const onDrop = useCallback((e: React.DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    setIsDragging(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      handleFile(e.dataTransfer.files[0]);
    }
  }, [onImageSelect]);

  const onDragOver = useCallback((e: React.DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    setIsDragging(true);
  }, []);

  const onDragLeave = useCallback((e: React.DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    setIsDragging(false);
  }, []);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      handleFile(e.target.files[0]);
    }
  };

  const clearImage = (e: React.MouseEvent) => {
    e.stopPropagation();
    setPreview(null);
    // You might want to notify the parent to clear the image, but simplicity works for now
  };

  return (
    <div className="w-full max-w-2xl mx-auto">
      <div
        onDrop={onDrop}
        onDragOver={onDragOver}
        onDragLeave={onDragLeave}
        className={`
          relative group cursor-pointer
          border-3 border-dashed rounded-3xl transition-all duration-300 ease-in-out
          flex flex-col items-center justify-center p-8
          min-h-[300px]
          ${isDragging 
            ? 'border-emerald-500 bg-emerald-50 scale-[1.02]' 
            : 'border-slate-300 hover:border-emerald-400 hover:bg-slate-50'
          }
          ${preview ? 'border-none p-0 overflow-hidden bg-slate-900' : ''}
        `}
      >
        <input
          type="file"
          accept="image/*"
          className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
          onChange={handleInputChange}
          disabled={isLoading}
        />

        {preview ? (
          <div className="relative w-full h-full flex items-center justify-center bg-black/90 rounded-3xl overflow-hidden">
            <img 
              src={preview} 
              alt="Preview" 
              className="max-h-[500px] w-auto object-contain"
            />
            {!isLoading && (
              <button
                onClick={clearImage}
                className="absolute top-4 right-4 z-20 bg-white/20 hover:bg-white/40 backdrop-blur-md text-white p-2 rounded-full transition-colors"
              >
                <X className="w-5 h-5" />
              </button>
            )}
            {isLoading && (
              <div className="absolute inset-0 z-30 flex items-center justify-center bg-black/60 backdrop-blur-sm">
                 <div className="flex flex-col items-center gap-4">
                   <div className="w-12 h-12 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin"></div>
                   <p className="text-emerald-400 font-medium animate-pulse">Analyzing Food Quality...</p>
                 </div>
              </div>
            )}
          </div>
        ) : (
          <div className="text-center space-y-4 pointer-events-none">
            <div className={`
              w-20 h-20 mx-auto rounded-full flex items-center justify-center
              ${isDragging ? 'bg-emerald-200 text-emerald-700' : 'bg-slate-100 text-slate-400 group-hover:bg-emerald-100 group-hover:text-emerald-600'}
              transition-colors duration-300
            `}>
              {isDragging ? <Upload className="w-10 h-10" /> : <ImageIcon className="w-10 h-10" />}
            </div>
            <div>
              <p className="text-xl font-semibold text-slate-700">
                {isDragging ? 'Drop it here!' : 'Upload Food Image'}
              </p>
              <p className="text-sm text-slate-500 mt-2">
                Drag & drop or click to browse
              </p>
            </div>
            <div className="flex gap-2 justify-center mt-4">
              <span className="px-3 py-1 bg-slate-100 rounded-full text-xs text-slate-500">JPG</span>
              <span className="px-3 py-1 bg-slate-100 rounded-full text-xs text-slate-500">PNG</span>
              <span className="px-3 py-1 bg-slate-100 rounded-full text-xs text-slate-500">WEBP</span>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default ImageUploader;

import React, { useState } from 'react';
import ImageUploader from './components/ImageUploader';
import AnalysisResult from './components/AnalysisResult';
import { analyzeFoodImage } from './services/geminiService';
import { FoodAnalysis } from './types';
import { ScanSearch, ShieldCheck, ChefHat } from 'lucide-react';

const App: React.FC = () => {
  const [analysisResult, setAnalysisResult] = useState<FoodAnalysis | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleImageSelect = async (file: File) => {
    setIsLoading(true);
    setError(null);
    setAnalysisResult(null);

    try {
      const result = await analyzeFoodImage(file);
      setAnalysisResult(result);
    } catch (err: any) {
      setError(err.message || "An unexpected error occurred.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 selection:bg-emerald-100 selection:text-emerald-900 pb-20">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-40">
        <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-emerald-600 p-2 rounded-lg">
              <ShieldCheck className="w-6 h-6 text-white" />
            </div>
            <h1 className="text-xl font-bold bg-gradient-to-r from-emerald-600 to-teal-600 bg-clip-text text-transparent">
              FreshGuard AI
            </h1>
          </div>
          <div className="hidden md:flex items-center gap-6 text-sm font-medium text-slate-500">
             <span className="flex items-center gap-1 hover:text-emerald-600 cursor-pointer transition-colors">
               <ScanSearch className="w-4 h-4" /> Visual Analysis
             </span>
             <span className="flex items-center gap-1 hover:text-emerald-600 cursor-pointer transition-colors">
               <ChefHat className="w-4 h-4" /> Food Safety
             </span>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-6xl mx-auto px-4 py-12">
        <div className="text-center mb-12 space-y-4">
          <h2 className="text-4xl md:text-5xl font-extrabold text-slate-900 tracking-tight">
            Is your food <span className="text-emerald-600">safe to eat?</span>
          </h2>
          <p className="text-lg text-slate-600 max-w-2xl mx-auto">
            Upload a photo of any food item. Our advanced AI will analyze its freshness, detect potential spoilage, and provide safety recommendations instantly.
          </p>
        </div>

        {/* Upload Section */}
        <div className="mb-12">
          <ImageUploader onImageSelect={handleImageSelect} isLoading={isLoading} />
        </div>

        {/* Error Message */}
        {error && (
          <div className="max-w-2xl mx-auto mb-8 p-4 bg-rose-50 border border-rose-200 rounded-xl text-rose-700 flex items-center gap-3">
             <div className="p-2 bg-rose-100 rounded-full shrink-0">
               <ShieldCheck className="w-5 h-5 text-rose-600" />
             </div>
             <div>
               <p className="font-semibold">Analysis Failed</p>
               <p className="text-sm">{error}</p>
             </div>
          </div>
        )}

        {/* Results Section */}
        {analysisResult && (
          <div id="results">
            <AnalysisResult data={analysisResult} />
          </div>
        )}
      </main>

       {/* Footer */}
       <footer className="border-t border-slate-200 bg-white mt-auto">
        <div className="max-w-6xl mx-auto px-4 py-8 text-center text-slate-400 text-sm">
          <p>&copy; {new Date().getFullYear()} FreshGuard AI. Powered by Google Gemini.</p>
        </div>
      </footer>
    </div>
  );
};

export default App;

