    Analyze the uploaded food image and provide a detailed, structured food quality assessment.

    Instructions:
    1. Identify the food item.
    2. Analyze visual appearance (Color, Texture, Moisture, Mold, Discoloration).
    3. Classify freshness based ONLY on visual cues.
    4. Provide a Freshness Confidence Score (0-100).
    5. Explain reasoning.
    6. Identify health risks.
    7. Estimate shelf life.
    8. Provide safety advice.
    9. Estimate nutrition.
    10. Include Indian food specific observations if applicable.
    11. Offer waste reduction tips.
    12. Suggest 3 recipes or culinary uses (if safe).
    13. Provide specific storage recommendations.
    14. Detect potential allergens.

    Important: Do not make absolute medical claims. State this is AI-based visual estimation.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: file.type,
              data: base64Data,
            },
          },
          {
            text: prompt,
          },
        ],
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: analysisSchema,
        systemInstruction: "You are a helpful, expert food safety AI assistant.",
      },
    });

    const text = response.text;
    if (!text) {
      throw new Error("No response received from AI.");
    }

    const result = JSON.parse(text) as FoodAnalysis;

    // Add client-side metadata
    return {
      ...result,
      id: crypto.randomUUID(),
      timestamp: Date.now()
    };
  } catch (error) {
    console.error("Analysis Error:", error);
    throw new Error("Failed to analyze image. Please try again.");
  }
};

import React from 'react';
import { FoodAnalysis } from '../types';
import { Clock, ChevronRight, History } from 'lucide-react';

interface ScanHistoryProps {
  history: FoodAnalysis[];
  onSelect: (item: FoodAnalysis) => void;
  onClear: () => void;
}

const ScanHistory: React.FC<ScanHistoryProps> = ({ history, onSelect, onClear }) => {
  if (history.length === 0) return null;

  const formatDate = (timestamp: number) => {
    return new Intl.DateTimeFormat('en-US', {
      month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit'
    }).format(new Date(timestamp));
  };

  const getStatusColor = (status: string) => {
     switch (status) {
      case "Fresh and Safe to Eat": return "text-emerald-600 bg-emerald-50";
      case "Questionable (Consume with Caution)": return "text-amber-600 bg-amber-50";
      case "Spoiled or Unsafe to Eat": return "text-rose-600 bg-rose-50";
      default: return "text-gray-600 bg-gray-50";
    }
  };

  return (
    <div className="mt-12 border-t border-slate-200 pt-8 animate-fade-in">
      <div className="flex items-center justify-between mb-6">
        <h3 className="text-xl font-bold text-slate-800 flex items-center gap-2">
          <History className="w-5 h-5 text-slate-500" />
          Recent Scans
        </h3>
        <button 
          onClick={onClear}
          className="text-sm text-slate-400 hover:text-rose-500 transition-colors"
        >
          Clear History
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {history.map((item) => (
          <button
            key={item.id || item.timestamp}
            onClick={() => onSelect(item)}
            className="text-left group bg-white p-4 rounded-xl border border-slate-200 hover:border-emerald-300 hover:shadow-md transition-all duration-200 flex flex-col gap-2"
          >
            <div className="flex justify-between items-start w-full">
              <span className="font-bold text-slate-800 truncate pr-2">{item.foodDetected}</span>
              <span className="text-xs text-slate-400 whitespace-nowrap flex items-center gap-1">
                 <Clock className="w-3 h-3" />
                 {item.timestamp ? formatDate(item.timestamp) : 'Unknown'}
              </span>
            </div>

            <div className={`text-xs px-2 py-1 rounded-md self-start font-medium ${getStatusColor(item.freshnessStatus)}`}>
              {item.freshnessStatus}
            </div>

            <div className="mt-auto pt-2 flex items-center text-emerald-600 text-sm font-medium opacity-0 group-hover:opacity-100 transition-opacity">
              View Details <ChevronRight className="w-4 h-4 ml-1" />
            </div>
          </button>
        ))}
      </div>
    </div>
  );
};

